const body = $input.first().json.body ?? $input.first().json;
const { email, name, company, source, utmSource } = body;

if (!email || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(String(email))) {
  throw new Error('Valid email required');
}

return [{
  json: {
    email: String(email).toLowerCase().trim(),
    name: name ?? null,
    company: company ?? null,
    source: source ?? 'n8n_webhook',
    utmSource: utmSource ?? null,
    pipelineStart: Date.now()
  }
}];

const prev = $('Validate Email').first().json;
const raw = $input.first().json;

let apolloData = {};
try {
  const person = raw.person ?? {};
  const org = person.organization ?? {};
  apolloData = {
    company_name: person.organization_name ?? org.name ?? prev.company ?? null,
    annual_revenue: org.annual_revenue ?? null,
    employee_count: org.estimated_num_employees ?? null,
    industry: org.industry ?? null,
    tech_stack: org.technology_names ?? [],
    funding_stage: org.latest_funding_stage ?? null,
    headquarters: org.city && org.country
      ? `${org.city}, ${org.country}`
      : (org.city ?? org.country ?? null),
    linkedin_url: person.linkedin_url ?? org.linkedin_url ?? null
  };
} catch(e) {}

return [{ json: { ...prev, apolloData } }];

const prev = $('Parse Apollo').first().json;
const raw = $input.first().json;

let perplexityData = { summary: null, intent_signals: [] };
try {
  const text = raw.choices?.[0]?.message?.content ?? '';
  const signalKeywords = ['hiring', 'funding', 'launch', 'expansion', 'partnership', 'acquisition', 'growth'];
  perplexityData = {
    summary: text.trim() || null,
    intent_signals: signalKeywords.filter(k => text.toLowerCase().includes(k))
  };
} catch(e) {}

return [{ json: { ...prev, perplexityData } }];

const prev = $input.first().json;
const { apolloData } = prev;

const DEFAULTS = {
  annual_revenue: 0,
  employee_count: 50,
  funding_stage: 'Unknown',
  tech_stack: [],
  industry: 'Technology'
};

const enriched = { ...apolloData };
const null_fields_patched = [];

for (const [field, def] of Object.entries(DEFAULTS)) {
  const v = apolloData[field];
  if (v === null || v === undefined || v === '' || (Array.isArray(v) && v.length === 0)) {
    enriched[field] = def;
    null_fields_patched.push(field);
  }
}

return [{ json: { ...prev, enriched, null_fields_patched } }];

const d = $input.first().json;
const { email, name, enriched, perplexityData, null_fields_patched } = d;

const leadContext = [
  `Email: ${email}`,
  name ? `Name: ${name}` : '',
  `Company: ${enriched.company_name ?? 'Unknown'}`,
  `Industry: ${enriched.industry}`,
  `Employees: ${enriched.employee_count}`,
  `Revenue: ${enriched.annual_revenue ? '$' + Number(enriched.annual_revenue).toLocaleString() : 'Unknown'}`,
  `Funding: ${enriched.funding_stage}`,
  `Tech Stack: ${Array.isArray(enriched.tech_stack) ? enriched.tech_stack.slice(0,8).join(', ') : 'Unknown'}`,
  enriched.headquarters ? `HQ: ${enriched.headquarters}` : '',
  perplexityData.summary ? `\nResearch:\n${perplexityData.summary}` : '',
  perplexityData.intent_signals?.length ? `Intent Signals: ${perplexityData.intent_signals.join(', ')}` : '',
  null_fields_patched.length ? `\n(Defaults applied to: ${null_fields_patched.join(', ')})` : ''
].filter(Boolean).join('\n');

const payload = {
  model: 'claude-opus-4-6',
  max_tokens: 2000,
  tools: [{
    name: 'score_lead',
    description: 'Score an inbound B2B lead and generate personalized outreach',
    input_schema: {
      type: 'object',
      properties: {
        vip_score: { type: 'integer', description: 'Score 0-100' },
        vip_tier: { type: 'string', enum: ['VIP','High','Medium','Low'] },
        score_rationale: { type: 'string' },
        outreach_draft: {
          type: 'object',
          properties: { subject: { type: 'string' }, body: { type: 'string' } },
          required: ['subject','body'],
          additionalProperties: false
        },
        recommended_action: { type: 'string' },
        confidence_interval: { type: 'string' }
      },
      required: ['vip_score','vip_tier','score_rationale','outreach_draft','recommended_action','confidence_interval'],
      additionalProperties: false
    }
  }],
  tool_choice: { type: 'tool', name: 'score_lead' },
  system: 'You are a revenue operations AI scoring inbound leads for Solen. ICP: B2B SaaS, Series A-C, 50-500 employees, $5M-$100M ARR, RevOps/Sales Ops team. Score 0-100. VIP=80+, High=60-79, Medium=40-59, Low=<40. Write personalized outreach referencing specific company details.',
  messages: [{ role: 'user', content: `Score this lead and draft outreach:\n\n${leadContext}` }]
};

return [{ json: { ...d, claudePayload: JSON.stringify(payload) } }];

const prev = $('Null-Safe Router').first().json;
const inputItem = $input.first();
const rawJson = inputItem.json;

let claudeResponse;

if (rawJson && rawJson.content) {
  claudeResponse = rawJson;
} else if (rawJson && rawJson.data && typeof rawJson.data === 'string') {
  try { claudeResponse = JSON.parse(rawJson.data); } catch(e) {}
} else if (rawJson && rawJson.data && Array.isArray(rawJson.data)) {
  try { claudeResponse = JSON.parse(Buffer.from(rawJson.data).toString('utf-8')); } catch(e) {}
} else if (inputItem.binary) {
  const key = Object.keys(inputItem.binary)[0];
  const b64 = inputItem.binary[key]?.data;
  if (b64) { try { claudeResponse = JSON.parse(Buffer.from(b64, 'base64').toString('utf-8')); } catch(e) {} }
}

if (!claudeResponse) {
  throw new Error('Could not decode Claude response. rawJson keys: ' + Object.keys(rawJson ?? {}).join(','));
}

// Claude error response (type:'error') has no content array
if (claudeResponse.type === 'error') {
  throw new Error('Claude API error: ' + JSON.stringify(claudeResponse.error ?? claudeResponse));
}

const toolUse = claudeResponse.content?.find(b => b.type === 'tool_use');
if (!toolUse) {
  throw new Error('No tool_use. stop_reason=' + claudeResponse.stop_reason + ' content=' + JSON.stringify(claudeResponse.content ?? null));
}

return [{ json: { ...prev, score: toolUse.input } }];
